<?php require_once __DIR__.'/../includes/auth_check.php';$id=(int)($_GET['id']??$_POST['id']??0);$s=$pdo->prepare('SELECT * FROM cars WHERE id=:id');$s->execute(['id'=>$id]);$car=$s->fetch();if(!$car)exit('Voiture introuvable');$error='';if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??'')){try{$img=upload_img($_FILES['image']??[]) ?: $car['image_path'];$st=$pdo->prepare('UPDATE cars SET name=:name,slug=:slug,category=:category,transmission=:transmission,fuel_type=:fuel_type,seats=:seats,price_per_day=:price,image_path=:image,description=:description,features=:features,deposit_info=:deposit,documents_required=:docs,insurance_info=:insurance,status=:status WHERE id=:id');$st->execute(['name'=>trim($_POST['name']),'slug'=>trim($_POST['slug'])?:slugify($_POST['name']),'category'=>trim($_POST['category']),'transmission'=>trim($_POST['transmission']),'fuel_type'=>trim($_POST['fuel_type']),'seats'=>(int)$_POST['seats'],'price'=>(float)$_POST['price_per_day'],'image'=>$img,'description'=>trim($_POST['description']),'features'=>trim($_POST['features']),'deposit'=>trim($_POST['deposit_info']),'docs'=>trim($_POST['documents_required']),'insurance'=>trim($_POST['insurance_info']),'status'=>$_POST['status'],'id'=>$id]);redirect('/admin/cars/');}catch(Throwable $e){$error='Impossible de modifier la voiture.';}}include __DIR__.'/../includes/admin_header.php';?><h1>Modifier <?=e($car['name'])?></h1><?php if($error):?><p class="error"><?=e($error)?></p><?php endif;?><form method="post" enctype="multipart/form-data" class="admin-form"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($id)?>"><label>Nom<input name="name" value="<?=e($car['name']??'')?>" required></label><label>Slug<input name="slug" value="<?=e($car['slug']??'')?>"></label><label>Catégorie<input name="category" value="<?=e($car['category']??'Economique')?>" required></label><label>Transmission<select name="transmission"><option>Manuelle</option><option>Automatique</option></select></label><label>Carburant<input name="fuel_type" value="<?=e($car['fuel_type']??'Diesel')?>" required></label><label>Places<input type="number" name="seats" value="<?=e($car['seats']??5)?>"></label><label>Prix / jour<input type="number" step="0.01" name="price_per_day" value="<?=e($car['price_per_day']??'300')?>" required></label><label>Image<input type="file" name="image" accept="image/jpeg,image/png,image/webp"></label><label>Description<textarea name="description"><?=e($car['description']??'')?></textarea></label><label>Features<textarea name="features"><?=e($car['features']??'')?></textarea></label><label>Caution<textarea name="deposit_info"><?=e($car['deposit_info']??'')?></textarea></label><label>Documents<textarea name="documents_required"><?=e($car['documents_required']??'')?></textarea></label><label>Assurance<textarea name="insurance_info"><?=e($car['insurance_info']??'')?></textarea></label><label>Statut<select name="status"><option value="available">Disponible</option><option value="rented">Louée</option><option value="maintenance">Maintenance</option><option value="hidden">Masquée</option></select></label><button class="btn primary">Mettre à jour</button></form><?php include __DIR__.'/../includes/admin_footer.php';?>